        print("Creating source distribution...")
        subprocess.run([sys.executable, "setup.py", "sdist"], check=True)
        print(f"Source distribution created in '{dist_dir}'.")

        # Option 2 (Alternative/Additional): Copy essential files to a deployment directory
        # This approach is useful if you want a simple directory structure for deployment
